// // This module implements a clock-gated flip-flop that updates its output on the falling edge of the clock when the enable signal is high.
module clock_gated_ff (
    input wire clk,
    input wire enable,
    input wire rst,
    input wire d,
    output reg q
);
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            q <= 0;
        end else if (enable) begin
            q <= d;
        end
    end
endmodule
